  photo VARCHAR(255) DEFAULT NULL,
  avaliableForClass VARCHAR(255) DEFAULT NULL,
  language VARCHAR(255) DEFAULT NULL,
  addmissionDate TIMESTAMP DEFAULT NULL,
  endClassDate TIMESTAMP DEFAULT NULL,
  studentTypeID INTEGER,
  classTypeID INTEGER,
  addmissionNo VARCHAR(255) DEFAULT NULL,
  branchID INTEGER,
  note VARCHAR(255) DEFAULT NULL,
  status VARCHAR(255) DEFAULT 'Active',
  createdAt TIMESTAMP NOT NULL,
  updatedAt TIMESTAMP NOT NULL,
  teacherNo VARCHAR(255) DEFAULT NULL,
  KEY teacherTypeID (teacherTypeID),
  KEY studentTypeID (studentTypeID),
  KEY classTypeID (classTypeID),
  KEY branchID (branchID),
  CONSTRAINT Account_ibfk_616 FOREIGN KEY (teacherTypeID) REFERENCES TeacherType (id) ON UPDATE CASCADE,
  CONSTRAINT Account_ibfk_617 FOREIGN KEY (studentTypeID) REFERENCES StudentType (id) ON UPDATE CASCADE,
  CONSTRAINT Account_ibfk_618 FOREIGN KEY (classTypeID) REFERENCES ClassType (id) ON UPDATE CASCADE,
