DROP TABLE IF EXISTS ClassEvents;

CREATE TABLE ClassEvents (
  id SERIAL PRIMARY KEY,
  classId INTEGER,
  title VARCHAR(255) NOT NULL,
  startDate TIMESTAMP NOT NULL,
  endDate TIMESTAMP NOT NULL,
  link VARCHAR(255) DEFAULT NULL,
  color VARCHAR(255) DEFAULT NULL,
  updateBy INTEGER NOT NULL,
  note VARCHAR(255) DEFAULT NULL,
  createdAt TIMESTAMP NOT NULL,
  updatedAt TIMESTAMP NOT NULL,
  KEY classId (classId),
  KEY updateBy (updateBy),
  CONSTRAINT ClassEvents_ibfk_213 FOREIGN KEY (classId) REFERENCES Class (id) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT ClassEvents_ibfk_214 FOREIGN KEY (updateBy) REFERENCES Account (id) ON DELETE CASCADE ON UPDATE CASCADE
) ;
