-- Table structure for table ClassStudy
--
DROP TABLE IF EXISTS ClassStudy;

CREATE TABLE ClassStudy (
  id SERIAL PRIMARY KEY,
  classID INTEGER NOT NULL,
  day VARCHAR(255) NOT NULL,
  startTime time NOT NULL,
  endTime time NOT NULL,
  note VARCHAR(255) DEFAULT NULL,
  createdAt TIMESTAMP NOT NULL,
  updatedAt TIMESTAMP NOT NULL,
  KEY classID (classID),
  CONSTRAINT ClassStudy_ibfk_1 FOREIGN KEY (classID) REFERENCES Class (id) ON DELETE CASCADE ON UPDATE CASCADE
) ;
