--
-- Table structure for table MyMaterial
--
DROP TABLE IF EXISTS MyMaterial;

CREATE TABLE MyMaterial (
  id SERIAL PRIMARY KEY,
  accountID INTEGER NOT NULL,
  materialID INTEGER NOT NULL,
  createdAt TIMESTAMP NOT NULL,
  updatedAt TIMESTAMP NOT NULL,
  KEY accountID (accountID),
  KEY materialID (materialID),
  CONSTRAINT MyMaterial_ibfk_287 FOREIGN KEY (accountID) REFERENCES Account (id) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT MyMaterial_ibfk_288 FOREIGN KEY (materialID) REFERENCES Materials (id) ON DELETE CASCADE ON UPDATE CASCADE
) ;
