--
-- Table structure for table PointStructure
--
DROP TABLE IF EXISTS PointStructure;

CREATE TABLE PointStructure (
  id SERIAL PRIMARY KEY,
  accountID INTEGER NOT NULL,
  updateDate TIMESTAMP DEFAULT NULL,
  totalPoint int DEFAULT '0',
  pointUp int DEFAULT '0',
  pointDown int DEFAULT '0',
  pointAfterUpdate VARCHAR(255) DEFAULT NULL,
  resonalForUpdate VARCHAR(255) DEFAULT NULL,
  updateBy INTEGER NOT NULL,
  createdAt TIMESTAMP NOT NULL,
  updatedAt TIMESTAMP NOT NULL,
  KEY accountID (accountID),
  KEY updateBy (updateBy),
  CONSTRAINT PointStructure_ibfk_1 FOREIGN KEY (accountID) REFERENCES Account (id) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT PointStructure_ibfk_2 FOREIGN KEY (updateBy) REFERENCES Account (id) ON DELETE CASCADE ON UPDATE CASCADE
) ;
